class Solution:
    def splitArray(self, nums):
        n = len(nums)
        best = -1
        for i in range(n - 1):
            left = nums[:i + 1]
            right = nums[i + 1:]
            ok = all(left[j] < left[j + 1] for j in range(len(left) - 1))
            ok = ok and all(right[j] > right[j + 1] for j in range(len(right) - 1))
            if ok:
                d = abs(sum(left) - sum(right))
                if best == -1 or d < best:
                    best = d
        return best

