class Solution:
    def splitArray(self, nums):
        n = len(nums)
        inc = 0
        while inc + 1 < n and nums[inc] < nums[inc + 1]:
            inc += 1
        dec = n - 1
        while dec - 1 >= 0 and nums[dec - 1] > nums[dec]:
            dec -= 1
        total = sum(nums)
        prefix = 0
        best = -1
        for i in range(n - 1):
            prefix += nums[i]
            if i <= inc and i + 1 >= dec:
                right = total - prefix
                d = abs(prefix - right)
                if best == -1 or d < best:
                    best = d
        return best

