var splitArray = function(nums) {
    const n = nums.length;
    let inc = 0;
    while (inc + 1 < n && nums[inc] < nums[inc + 1]) inc++;
    let dec = n - 1;
    while (dec - 1 >= 0 && nums[dec - 1] > nums[dec]) dec--;
    let total = 0;
    for (const v of nums) total += v;
    let prefix = 0, best = -1;
    for (let i = 0; i < n - 1; i++) {
        prefix += nums[i];
        if (i <= inc && i + 1 >= dec) {
            const right = total - prefix;
            const d = Math.abs(prefix - right);
            if (best === -1 || d < best) best = d;
        }
    }
    return best;
};
